import { Component, createMemo, lazy, on } from 'solid-js';
import type {
  InputColorProps,
  InputDateProps,
  InputNumberProps,
  InputOTPProps,
  InputPasswordProps,
  InputRangeProps,
  InputTextAreaProps,
  InputTextProps,
} from './input.types';
import { InputRadioProps } from './variants/input-radio';

const InputText = lazy(() => import('./variants/input-text').then(m => ({ default: m.InputText })));
const InputNumber = lazy(() =>
  import('./variants/input-number').then(m => ({ default: m.InputNumber })),
);
const InputColor = lazy(() =>
  import('./variants/input-color').then(m => ({ default: m.InputColor })),
);
const InputPassword = lazy(() =>
  import('./variants/input-password').then(m => ({ default: m.InputPassword })),
);
const InputDate = lazy(() => import('./variants/input-date').then(m => ({ default: m.InputDate })));
const InputRange = lazy(() =>
  import('./variants/input-range').then(m => ({ default: m.InputRange })),
);
const InputTextArea = lazy(() =>
  import('./variants/input-textarea').then(m => ({ default: m.InputTextArea })),
);
const InputOTP = lazy(() => import('./variants/input-otp').then(m => ({ default: m.InputOTP })));

const InputRadio = lazy(() =>
  import('./variants/input-radio').then(m => ({ default: m.InputRadio })),
);

type InputProps =
  | InputTextProps
  | InputColorProps
  | InputDateProps
  | InputNumberProps
  | InputPasswordProps
  | InputRangeProps
  | InputTextAreaProps
  | InputOTPProps
  | InputRadioProps;

export const Input: Component<InputProps> & {
  Text: Component<InputTextProps>;
  TextArea: Component<InputTextAreaProps>;
  Color: Component<InputColorProps>;
  Date: Component<InputDateProps>;
  Number: Component<InputNumberProps>;
  Password: Component<InputPasswordProps>;
  Range: Component<InputRangeProps>;
  OTP: Component<InputOTPProps>;
  Radio: Component<InputRadioProps>;
} = props => {
  const render = createMemo(
    on(
      () => props.type,
      () => {
        switch (props.type) {
          case 'text':
            return <InputText {...props} />;
          case 'textarea':
            return <InputTextArea {...props} />;
          case 'number':
            return <InputNumber {...props} />;
          case 'password':
            return <InputPassword {...props} />;
          case 'color':
            return <InputColor {...props} />;
          case 'date':
            return <InputDate {...props} />;
          case 'range':
            return <InputRange {...props} />;
          case 'otp':
            return <InputOTP {...props} />;
          case 'radio':
            return <InputRadio {...props} />;
          default:
            return <InputText {...(props as InputTextProps)} />;
        }
      },
    ),
  );
  return <>{render()}</>;
};

Input.Text = InputText as Component<InputTextProps>;
Input.TextArea = InputTextArea as Component<InputTextAreaProps>;
Input.Color = InputColor as Component<InputColorProps>;
Input.Date = InputDate as Component<InputDateProps>;
Input.Number = InputNumber as Component<InputNumberProps>;
Input.Password = InputPassword as Component<InputPasswordProps>;
Input.Range = InputRange as Component<InputRangeProps>;
Input.OTP = InputOTP as Component<InputOTPProps>;
Input.Radio = InputRadio as Component<InputRadioProps>;
export type { InputVariantsProps, TextAreaVariantsProps } from './input.utils';
